// search.js — instant client-side lesson search. Mounts into #coursesearch
// (input + results) and filters window.SEARCH_INDEX (generated by tools/quiz-data.mjs)
// by case-insensitive substring over title, blurb, and headings.
// ponytail: links to the lesson top — headings have no ids yet. Add heading ids
// + #anchor deep-links when readers ask for jump-to-section.
(function () {
  var host = document.getElementById("coursesearch"), IDX = window.SEARCH_INDEX;
  if (!host || !IDX) return;

  var input = document.createElement("input");
  input.type = "search";
  input.className = "searchbox";
  input.placeholder = "Search lessons — e.g. hooks, context, migrations";
  input.setAttribute("aria-label", "Search lessons");
  var results = document.createElement("ul");
  results.className = "searchresults";
  results.hidden = true;
  host.appendChild(input);
  host.appendChild(results);

  input.addEventListener("input", function () {
    var q = input.value.trim().toLowerCase();
    results.innerHTML = "";
    if (!q) { results.hidden = true; return; }
    var hits = IDX.filter(function (l) {
      return (l.title + " " + l.blurb + " " + l.headings.join(" ")).toLowerCase().indexOf(q) !== -1;
    });
    results.hidden = false;
    if (!hits.length) {
      results.innerHTML = '<li class="noresult">No lessons match “' + input.value.trim() + '”.</li>';
      return;
    }
    hits.forEach(function (l) {
      var snip = l.headings.filter(function (h) { return h.toLowerCase().indexOf(q) !== -1; })[0];
      var li = document.createElement("li");
      var a = document.createElement("a");
      a.href = "lessons/" + l.slug + ".html";
      a.innerHTML = '<span class="sn">Lesson ' + l.n + '</span> <span class="st">' + l.title + "</span>" +
        (snip ? ' <span class="sh">— ' + snip + "</span>" : "");
      li.appendChild(a);
      results.appendChild(li);
    });
  });
})();
